script.text:
      &OutlineEntry;
      /* <flatten type="Javascript"> */
function init$StockVarianceReportforConsolidate$(f) {f.getItem('so_ct')._idle = true;}
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  f._looking = f.getItem('so_ct')._controlBehavior;
  f._looking.add_loading(onclick$StockVarianceReportforConsolidate$Before$Loading);
}
function close$VoucherFilter$(f) {
  try {f._looking.remove_loading(on$StockVarianceReportforConsolidate$Before$Loading);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
			var g = f.grid;
      g._voucherNum = f.getItemValue('so_ct').toUpperCase();
      g._alterTitle = [null, [['%s', g._voucherNum, true]]];
      g._arrValue = [];
	    break;
	  default:
      break;
	}
}

function onclick$StockVarianceReportforConsolidate$Before$Loading(sender, e) {
  var f = sender._element.parentForm;
  if ((!f.validFields('ngay_ct1')) || (!f.validFields('ngay_ct2'))) e.type.cancelEvent = true;
  else {
    var g = f.grid, w = g.get_element().parentForm;
    var d1 = f.getItemValue('ngay_ct1'), d2 = f.getItemValue('ngay_ct2');
    a = [
      {Name: 'd1', Type: 'DateTime', Value: d1},
      {Name: 'd2', Type: 'DateTime', Value: d2}
    ];
    sender.set_memvars(a);
  }
}

function on$Filter$Retrieve$QueryComplete(f, l) {
  var g = f.grid;
  g._denySave = l;
  if (l == 1) g._denyMessage = f._language == 'v' ? 'Đã khóa số liệu, kiểm tra lại ngày khóa số liệu kiểm kê.' : 'Check the Stocktaking data closing date.';
}
/* </flatten> */
